    bool pressure_stale = is_sensor_stale(controller->last_pressure_ms, input.now_ms, CONTROLLER_SENSOR_TIMEOUT_MS);
    bool door_stale = is_sensor_stale(controller->last_door_ms, input.now_ms, CONTROLLER_SENSOR_TIMEOUT_MS);

    if (pressure_stale || door_stale) {
        controller_set_safe_vent(controller);
        output.timed_out = true;
